#!/usr/bin/env node
import readline from 'node:readline/promises';
import { stdin as input, stdout as output } from 'node:process';
import os from 'node:os';
import { exec } from 'node:child_process';
import { SystemPromptManager, SessionTracker, ObservableModelProvider, startTraceServer, ChatMessage, ToolCall } from '@hajicli/core';
import {
  DeepSeekProvider,
  BashTool,
  ReadFileTool,
  WriteFileTool,
  EditFileTool,
  GlobalFindFilesTool,
  GrepSearchTool,
  WebSearchTool,
  WebFetchTool
} from '@hajicli/plugins';

// 原生 ANSI 终端转义色彩工具类，保持零外部依赖
const colors = {
  purple: (text: string) => `\x1b[35m${text}\x1b[0m`,
  boldPurple: (text: string) => `\x1b[1m\x1b[35m${text}\x1b[0m`,
  green: (text: string) => `\x1b[32m${text}\x1b[0m`,
  boldGreen: (text: string) => `\x1b[1m\x1b[32m${text}\x1b[0m`,
  yellow: (text: string) => `\x1b[33m${text}\x1b[0m`,
  boldYellow: (text: string) => `\x1b[1m\x1b[33m${text}\x1b[0m`,
  red: (text: string) => `\x1b[31m${text}\x1b[0m`,
  boldRed: (text: string) => `\x1b[1m\x1b[31m${text}\x1b[0m`,
  blue: (text: string) => `\x1b[34m${text}\x1b[0m`,
  boldBlue: (text: string) => `\x1b[1m\x1b[34m${text}\x1b[0m`,
  gray: (text: string) => `\x1b[90m${text}\x1b[0m`,
  cyan: (text: string) => `\x1b[36m${text}\x1b[0m`,
  bold: (text: string) => `\x1b[1m${text}\x1b[0m`,
};

// 像素画风格的大写 HAJI 启动 Logo
const LOGO = `
${colors.purple('█   █   ██   █████  █████')}
${colors.purple('█   █  █  █      █    █  ')}
${colors.purple('█████  ████      █    █  ')}
${colors.purple('█   █  █  █  █   █    █  ')}
${colors.purple('█   █  █  █  █████  █████')}
`;

// 绘制终端底部的固定输入框（两条横线包裹，下方留空隙）
function drawInputBox() {
  const rows = process.stdout.rows || 24;
  const cols = process.stdout.columns || 80;

  // 保存当前光标位置
  process.stdout.write('\x1b[s');

  // 1. 在 rows - 3 行绘制上边界分割线
  process.stdout.write(`\x1b[${rows - 3};1H\x1b[2K${colors.gray('─'.repeat(cols))}`);

  // 2. 在 rows - 2 行绘制输入行提示
  process.stdout.write(`\x1b[${rows - 2};1H\x1b[2K${colors.boldPurple('👤 你 › ')}`);

  // 3. 在 rows - 1 行绘制下边界分割线
  process.stdout.write(`\x1b[${rows - 1};1H\x1b[2K${colors.gray('─'.repeat(cols))}`);

  // 4. 清空 rows 最底行以保持下方与终端边缘的空隙
  process.stdout.write(`\x1b[${rows};1H\x1b[2K`);

  // 5. 恢复光标到 rows - 2 的输入行提示后方（列宽约为 10）
  process.stdout.write(`\x1b[${rows - 2};10H`);
}

async function main() {
  const apiKey = process.env.DEEPSEEK_API_KEY;
  if (!apiKey) {
    console.error(colors.boldRed('错误: 请在运行前将 DEEPSEEK_API_KEY 导出至环境变量。'));
    process.exit(1);
  }

  // 启动时清空终端屏幕，实现“置顶并开辟新页面”效果
  console.clear();

  const initialRows = process.stdout.rows || 24;
  // 设置滚动区域为 1 到 rows - 4 之间，使得底部的 4 行（行线、输入、行线、底边隙）保持静止
  process.stdout.write(`\x1b[1;${initialRows - 4}r`);
  // 将光标移入滚动区底部开始输出
  process.stdout.write(`\x1b[${initialRows - 4};1H`);

  console.log(LOGO);
  console.log(colors.gray('正在初始化大模型提供商、系统工具和 Trace 观测服务器...'));

  const tracker = new SessionTracker();
  const rawProvider = new DeepSeekProvider({ apiKey });
  const provider = new ObservableModelProvider(rawProvider, tracker);
  const systemPromptManager = new SystemPromptManager();
  const rl = readline.createInterface({ input, output });

  // 窗口大小调节监听，自适应滚动区域与输入底框
  process.stdout.on('resize', () => {
    const r = process.stdout.rows || 24;
    process.stdout.write(`\x1b[1;${r - 4}r`);
    drawInputBox();
  });

  // 在后台异步拉起 Trace 观测服务器，不自动打开浏览器
  startTraceServer(3000, false).catch(() => {});

  // 注册并实例化所有已实现的系统工具
  const tools = [
    new BashTool(),
    new ReadFileTool(),
    new WriteFileTool(),
    new EditFileTool(),
    new GlobalFindFilesTool(),
    new GrepSearchTool(),
    new WebSearchTool(),
    new WebFetchTool()
  ];

  const toolsMap = new Map(tools.map(t => [t.name, t]));
  const toolDefinitions = tools.map(t => t.definition);

  // 动态生成系统初始提示词，指导 AI 环境认知
  const systemPrompt = await systemPromptManager.generatePrompt({
    cwd: process.cwd(),
    os: os.platform() === 'win32' ? 'Windows (基于 Node.js 运行时环境)' : os.platform(),
    tools: tools.map(t => t.name)
  });

  console.log('==================================================');
  console.log(`🤖 ${colors.bold('haji 极简终端对话中心')} 启动成功！`);
  console.log(`   输入 ${colors.purple('/help')} 查看帮助指令，输入 ${colors.purple('/exit')} 退出会话。`);
  console.log('==================================================\n');

  // 初始化会话历史记录
  let messages: ChatMessage[] = [{ role: 'system', content: systemPrompt }];

  // 渲染一次初始输入底框
  drawInputBox();

  try {
    while (true) {
      // 优雅的用户提示符：光标已经在 rows - 2 的第 10 列，因此直接传入空字符串进行提问读取
      const userInput = await rl.question('');
      const trimmedInput = userInput.trim();

      // 回车后瞬间清除输入行多余字符，保持输入框静态洁净
      const currentRows = process.stdout.rows || 24;
      process.stdout.write(`\x1b[${currentRows - 2};1H\x1b[2K`);
      drawInputBox();

      if (!trimmedInput) continue;

      // 将光标移入上面的滚动执行区域底部，打印回显用户刚刚输入的内容并换行
      process.stdout.write(`\x1b[${currentRows - 4};1H\n`);
      console.log(`${colors.boldPurple('👤 你 › ')}${trimmedInput}`);

      // 解析斜杠内置命令
      if (trimmedInput.startsWith('/')) {
        const parts = trimmedInput.slice(1).split(' ');
        const command = parts[0].toLowerCase();

        if (command === 'exit' || command === 'quit') {
          console.log(colors.gray('再见！'));
          break;
        }
        if (command === 'clear') {
          messages = [{ role: 'system', content: systemPrompt }];
          console.log(colors.green('🧹 已成功重置会话上下文！'));
          drawInputBox();
          continue;
        }
        if (command === 'help') {
          console.log('\n' + colors.bold('可用斜杠指令列表:'));
          console.log(`  ${colors.purple('/help')}    - 显示帮助手册`);
          console.log(`  ${colors.purple('/clear')}   - 清空上下文，开始全新会话`);
          console.log(`  ${colors.purple('/viewer')}  - 打印或自动在浏览器打开 Trace 观测中心`);
          console.log(`  ${colors.purple('/exit')}    - 退出 haji 对话`);
          console.log('\n' + colors.bold('已注册的系统工具列表:'));
          tools.forEach(t => {
            console.log(`  ⚙️  ${colors.blue(t.name.padEnd(20))} : ${t.definition.function.description}`);
          });
          console.log('');
          drawInputBox();
          continue;
        }
        if (command === 'viewer') {
          const url = `http://localhost:3000/viewer?session=${tracker.getSessionId()}`;
          console.log(`📊 Trace 观测中心当前会话链接: ${colors.blue(url)}`);
          console.log(colors.gray('正在尝试在浏览器中打开链接...'));
          let openCmd = process.platform === 'win32' ? `start "" "${url}"` : (process.platform === 'darwin' ? `open "${url}"` : `xdg-open "${url}"`);
          exec(openCmd, () => {});
          drawInputBox();
          continue;
        }

        console.log(colors.red(`未知命令: /${command}。输入 /help 查看帮助。`));
        drawInputBox();
        continue;
      }

      // 记录用户消息到 Trace 与上下文
      tracker.recordUserInput(trimmedInput);
      messages.push({ role: 'user', content: trimmedInput });

      let keepCalling = true;
      while (keepCalling) {
        let currentToolCalls: ToolCall[] | null = null;

        // 启动异步 Spinner 加载动画（TTFT 思考期）
        let isThinking = true;
        const spinnerChars = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
        let spinIdx = 0;

        const rowsNow = process.stdout.rows || 24;
        process.stdout.write(`\x1b[${rowsNow - 4};1H\r${colors.boldGreen('🤖 haji › ')}⠋ ${colors.gray('思考中...')}`);
        const spinnerInterval = setInterval(() => {
          if (isThinking) {
            const r = process.stdout.rows || 24;
            process.stdout.write(`\x1b[${r - 4};1H\r${colors.boldGreen('🤖 haji › ')}${spinnerChars[spinIdx]} ${colors.gray('思考中...')}`);
            spinIdx = (spinIdx + 1) % spinnerChars.length;
          }
        }, 80);

