        speed = totalChars / generateDurationSec;
      }
    }

    this.tracker.recordLlmCall({
      id: crypto.randomUUID(),
      timestamp: new Date(startTime).toISOString(),
      model,
      messages,
      ttft,
      duration,
      speed,
      reasoningContent: accumulatedReasoning || undefined,
      content: accumulatedContent,
